actions.script:
def runtimePath = ec.factory.runtimePath
def componentDir = new File(runtimePath, "component")
def list = []
if (componentDir.exists()) {
    componentDir.eachDir { File compDir ->
        if (compDir.name.startsWith(".")) return

        boolean hasJson = false
        ['screen', 'entity', 'service'].each { sub ->
            def subDir = new File(compDir, sub)
            if (subDir.exists()) {
                subDir.eachFile { file -> if (file.name.endsWith(".json")) hasJson = true }
            }
        }
        if (hasJson) list.add(compDir.name)
    }
}
context.components = list.sort()

def runtimePath = ec.factory.runtimePath
def compDir = new File(runtimePath, "component/${componentName}")
def screenDir = new File(compDir, "screen")
def list = []
if (screenDir.exists()) {
    screenDir.eachFile { file -> if (file.name.endsWith(".json")) list.add(file.name.replace(".json", "")) }
}
context.screens = list.sort()
